declare(strict_types=1);namespace App\Services\ControlEscaneres\Schema;final class MigrationManifestVerifier{public function verify(string$manifest,string$migrationsDir):array{$data=json_decode((string)file_get_contents($manifest),true,512,JSON_THROW_ON_ERROR);$out=[];$previous=0;foreach($data['migrations']??[]as$m){$file=$migrationsDir.'/'.$m['file'];$actual=is_file($file)?hash_file('sha256',$file):null;$valid=$actual!==null&&hash_equals($m['sha256'],$actual)&&(int)$m['order']>$previous;$out[]=['order'=>(int)$m['order'],'file'=>$m['file'],'checksum'=>$m['sha256'],'valid'=>$valid,'depends_on'=>$m['depends_on'],'reversible'=>(bool)$m['reversible']];$previous=(int)$m['order'];}return$out;}}
